int format_metric_point(char* metric_name, char** label_keys, char** label_values, int label_count, char* metric_output) {
    // Validate critical input pointers
    if (metric_name == NULL || metric_output == NULL) {
        return -1;
    }

    // Validate label_count is non-negative
    if (label_count < 0) {
        return -1;
    }

    // Validate label arrays and their contents when labels are present
    if (label_count > 0) {
        if (label_keys == NULL || label_values == NULL) {
            return -1;
        }
        for (int i = 0; i < label_count; ++i) {
            if (label_keys[i] == NULL || label_values[i] == NULL) {
                return -1;
            }
        }
    }

    int total_len = 0;
    int written;

    // Write metric name
    written = sprintf(metric_output, "%s", metric_name);
    if (written < 0) {
        return -1;
    }
    total_len = written;

    // Only add braces and labels if label_count > 0
    if (label_count > 0) {
        // Write opening brace
        written = sprintf(metric_output + total_len, "{");
        if (written < 0) {
            return -1;
        }
        total_len += written;

        // Write label key-value pairs
        for (int i = 0; i < label_count; ++i) {
            // Add comma separator between labels
            if (i > 0) {
                written = sprintf(metric_output + total_len, ",");
                if (written < 0) {
                    return -1;
                }
                total_len += written;
            }

            // Write single label: key="value"
            written = sprintf(metric_output + total_len, "%s=\"%s\"", 
                             label_keys[i], label_values[i]);
            if (written < 0) {
                return -1;
            }
            total_len += written;
        }

        // Write closing brace
        written = sprintf(metric_output + total_len, "}");
        if (written < 0) {
            return -1;
        }
        total_len += written;
    }

    // Total length excludes null terminator as required
    return total_len;
}
